sql:
SELECT SUM(quantity) AS total_ventilators
FROM medical_resources
WHERE resource_type = 'ventilators';

SELECT hospital_name, total_beds
FROM hospital_data
ORDER BY total_beds DESC;

SELECT area_name
FROM areas
ORDER BY area_name;

external_knowledge:
- A low ventilator availability ratio implies that less than half of the total ventilator capacity is available for use, indicating a potential shortage.; 
- A low staff availability ratio signifies that less than 60% of the staff are available, which could compromise the quality of care.; 
- COVID-19 occupied Mobile Ventilation Bays indicate the number of Mobile Ventilation Bays currently in use for COVID-19 patients, serving as a measure of the pandemic's impact on healthcare resources.

sql:
SELECT city, COUNT(*) AS hospital_count
FROM hospital_data
GROUP BY city;

SELECT SUM(occupied_beds) AS total_occupied_beds
FROM hospital_data
WHERE hospital_id = 1;
